        import sailpoint.transformer.IdentityTransformer;
       
        
        Map identityModel = new HashMap();
        
        if(null != identityModel){
          identityModel.put("launcher",launcher);     
        }
        
                
        IdentityTransformer transformerModify = new IdentityTransformer(context);
        identityModel.put(IdentityTransformer.ATTR_TRANSFORMER_CLASS, transformerModify.getClass().getName());
        identityModel.put(IdentityTransformer.ATTR_TRANSFORMER_OPTIONS, "");

        return identityModel;

 import sailpoint.object.Identity;
String identityName = null;


if (identityModel != null && identityModel.get("contractorName") != null) {
identityName = identityModel.get("contractorName");
Identity identity=context.getObjectByName(Identity.class,identityName);
if(identity.getAttribute("type")==null){
	 identityModel.put("type","non-hr contractor");  
}
identityModel.remove("contractorName");
}
return identityName;

import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.object.QueryOptions;
import sailpoint.tools.Util;

Identity contractorIdn = context.getObjectByName(Identity.class, identityName);

Filter managerFilter = Filter.eq("contractorManager", identityName);
Filter activeFilter = Filter.eq("inactive", false);       
Filter filter = Filter.and(activeFilter, managerFilter);
             
QueryOptions queryOptions = new QueryOptions();
queryOptions.addFilter(filter);

List idList= context.getObjects(Identity.class,queryOptions);      
if ( null != idList && !idList.isEmpty() && identityModel != null && null != contractorIdn && Util.isNotNullOrEmpty(contractorIdn.getStringAttribute("isContractorManager")) && contractorIdn.getStringAttribute("isContractorManager").equalsIgnoreCase("true") && !identityModel.get("isContractorManager")) {          
	return true;       	
}

return false;

        import javax.faces.application.FacesMessage;
        import sailpoint.tools.Util;
		
		if (httpSession != null) {

        List currentMessages = httpSession.getAttribute("sailpoint.web.PageCodeBase.sessionMessages");  
        FacesMessage myMessage = null;

        String message = "Request has been submitted successfully.";
        myMessage = new FacesMessage(FacesMessage.SEVERITY_INFO,message+".","Success");  

        List myMessages = new ArrayList();  
        myMessages.add(myMessage);  
        httpSession.setAttribute("sailpoint.web.PageCodeBase.sessionMessages", myMessages);
