        import sailpoint.object.Custom;
        
        
        String locationID = "";
        String depID = "";
        String businessID ="";
        String locationName = "";
        String depName = "";
		
		Identity contractorIdn = context.getObjectByName(Identity.class, identityName);
        
        if ( identityModel != null && identityModel.get("dob") != null) {
        	identityModel.put("dob", encryptAES(identityModel.get("dob")));
        }
        
        if ( identityModel != null && identityModel.get("dbFields") != null) {
        	identityModel.remove("dbFields");
        }
        if ( identityModel != null && identityModel.get("domain") != null) {
        	identityModel.remove("domain");
        }
        if ( identityModel != null && identityModel.get("ssn") != null) {
        	identityModel.put("ssn", encryptAES(identityModel.get("ssn")));
        }
        if ( identityModel != null && identityModel.get("ctrexpDt") != null) {
        	identityModel.put("ctrexpDt", convertDateToString(identityModel.get("ctrexpDt")));
        }
        
        if(null != identityModel.get("isContractorManager")){
        		if(identityModel.get("isContractorManager")){
        			identityModel.put("isContractorManager","true");
        		}
        		else{
        			identityModel.put("isContractorManager","false");
        		}                
          }
        
      	Custom contractorCustom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        workflow.put("newContractorManager",identityModel.get("newContractorManager"));
        if (contractorCustom != null) {
        	identityModel.remove("newManager");
        	identityModel.remove("newContractorManager");
        identityModel.remove("launcher");
        identityModel.remove("helpText");
        	List metadataAttributes = contractorCustom.get("identityModelMetadata");
        	if (metadataAttributes != null && !metadataAttributes.isEmpty()) {
            for(String attr : metadataAttributes) {
              identityModel.remove(attr);
            }
          }
        }
        
        if(identityModel != null && contractorIdn !=null && Util.nullSafeCaseInsensitiveEq(contractorIdn.getAttribute("domain"),"AMITA")){
            if(Util.isNotNullOrEmpty(identityModel.get("location"))){
              locationName = identityModel.get("location");       
              identityModel.put("buildingId",getLocationID(locationName));
			  identityModel.put("streetAddress",getStreetAddress(locationName));
              identityModel.put("st",getState(locationName));
              identityModel.put("city",getCity(locationName));
              identityModel.put("postalCode",getPostalCode(locationName));
            }
            if(Util.isNotNullOrEmpty(identityModel.get("department"))){
              depName = identityModel.get("department");       
              identityModel.put("departmentNumber",getDepartmentID(depName));
            }
        		if(Util.isNotNullOrEmpty(identityModel.get("buildingId")) && Util.isNotNullOrEmpty(identityModel.get("departmentNumber"))){
              locationID = identityModel.get("buildingId");  
        			depID = identityModel.get("departmentNumber");  
              identityModel.put("businessUnit",getBusinessCode(depID,locationID));
            }
        		if(Util.isNotNullOrEmpty(identityModel.get("businessUnit"))){
              businessID = identityModel.get("businessUnit");       
              identityModel.put("businessUnitDescription",getBusinessDesc(businessID));
            }
        	}
        
         if(identityModel != null && Util.isNotNullOrEmpty(identityModel.get("location"))){
          	identityModel.put("locationDescription",identityModel.get("location"));
          }
		  if(identityModel != null){
			String displayName = identityModel.get("lastname")+", "+identityModel.get("firstname");
			identityModel.put("displayName",displayName);
		  }
		
        return identityModel;

        import sailpoint.object.Identity; 
        import sailpoint.object.Custom; 
        import sailpoint.object.ProvisioningPlan; 
        import sailpoint.object.ProvisioningPlan.AccountRequest; 
        import sailpoint.object.ProvisioningPlan.AccountRequest.Operation; 
        import sailpoint.object.ProvisioningPlan.AttributeRequest; 
        import sailpoint.object.ProvisioningPlan.Operation; 
        import sailpoint.tools.Util; 
        
        
        Identity contractorIdn = context.getObjectByName(Identity.class, identityName);
        List attributeList = new ArrayList(identityModel.keySet());
        ProvisioningPlan plan = new ProvisioningPlan();
       
        List nonApprovalAttributes = new ArrayList();
        Custom contractorCustom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
        if (contractorCustom != null && contractorCustom.get("UpdateAttributesForNoApproval") != null) {
        	nonApprovalAttributes = contractorCustom.get("UpdateAttributesForNoApproval");
        }
        
        if (contractorIdn != null && attributeList != null && !attributeList.isEmpty()) {
        
          for(String eachAttribute : attributeList) {
        		if ( eachAttribute != null && (eachAttribute.equals("ssn") || eachAttribute.equals("dob")) ) {
        			//handling encrypted attributes separately
        			String identityAttribute = null;
       			  String formAttribute = null;
       
        			if (contractorIdn.getAttribute(eachAttribute) != null) {
        				identityAttribute = decryptAES(contractorIdn.getAttribute(eachAttribute));
        				if(Util.isNullOrEmpty(identityAttribute)){
        					identityAttribute = contractorIdn.getAttribute(eachAttribute);
        				}
        			}
        			if (identityModel != null && identityModel.get(eachAttribute) != null) {
        				formAttribute = decryptAES(identityModel.get(eachAttribute));
        				if(Util.isNullOrEmpty(formAttribute)){
        					formAttribute = identityModel.get(eachAttribute);
        				}
        			}
        
        		 if ( !Util.nullSafeEq(identityAttribute, formAttribute, true) ) {
        
                 if (nonApprovalAttributes.contains(eachAttribute)) {
                    contractorIdn.setAttribute(eachAttribute, identityModel.get(eachAttribute));
                  } else {
                    approvalNeededAttributes.add(eachAttribute);
                  }
        			}
            } else if ( !Util.nullSafeEq(contractorIdn.getAttribute(eachAttribute), identityModel.get(eachAttribute), true) ) {
        		 
       			 if (nonApprovalAttributes.contains(eachAttribute)) {
        
                contractorIdn.setAttribute(eachAttribute, identityModel.get(eachAttribute));
              } else {
                approvalNeededAttributes.add(eachAttribute);
              } 
            }
          }
          context.startTransaction();
          context.saveObject(contractorIdn);
          context.commitTransaction();
        
       if (approvalNeededAttributes != null && !approvalNeededAttributes.isEmpty()){

 						AccountRequest acctReq = new AccountRequest();
          	acctReq.setApplication("IIQ");
          	acctReq.setNativeIdentity(identityName);
          	acctReq.setOperation(AccountRequest.Operation.Modify);
         
						for(String eachAttribute : approvalNeededAttributes) {
         	   acctReq.add(new AttributeRequest(eachAttribute, ProvisioningPlan.Operation.Set, identityModel.get(eachAttribute)));
         		}
        		plan.setIdentity(contractorIdn);
        		plan.add(acctReq);
       	 }
        }
        
        return plan;

						import sailpoint.object.Identity;
          import sailpoint.tools.Util;
          import sailpoint.api.ObjectUtil;
           
          String schemaVal = "none";
          boolean delegateRequest=false;
          ObjectUtil iiqObjUtil = new ObjectUtil();
          List workgroupMembers = new ArrayList();
		  
		  Filter wgFilter = Filter.eq("workgroup", true);
		  Filter wgNameFilter = Filter.like("name","Trusted Requesters", Filter.MatchMode.START);
		  QueryOptions qo = new QueryOptions();
		  qo.add(wgFilter,wgNameFilter);
		  List properties = new ArrayList();
		  List trustedRequestersWGs = new ArrayList();
		  properties.add("name");
		  Iterator iter = context.search(Identity.class, qo, properties);
		  while(iter.hasNext()) {
			Object[] workGroup = iter.next();
			if(workGroup != null) {
				trustedRequestersWGs.add(workGroup[0]);  
			}        
		  }
		  if(trustedRequestersWGs!=null && !trustedRequestersWGs.isEmpty()){
			for(String trustedRequestersWGName:trustedRequestersWGs){   
			if(Util.isNotNullOrEmpty(launcher)){      
				Identity delegateWGIdentity = context.getObjectByName(Identity.class,trustedRequestersWGName);
				Identity launcherIdentity = context.getObjectByName(Identity.class,launcher);
				if(delegateWGIdentity!=null && launcherIdentity!=null){
					if(launcherIdentity.isInWorkGroup(delegateWGIdentity)){
						delegateRequest=true;
						schemaVal = "none";
					}
				}
			}
		  }			
		 }
          if(!delegateRequest){
          if(Util.isNotNullOrEmpty(launcher) && null != identityModel && !Util.nullSafeCaseInsensitiveEq(identityModel.get("contractorManager"),launcher)){
          schemaVal = "manager, newManager";
          }
          else{
          schemaVal = "none";
			}
          }
          return schemaVal;

       
      	import sailpoint.object.IdentityRequest;
       
        boolean end = false;
        
        IdentityRequest idReq = context.getObjectByName(IdentityRequest.class,identityRequestId);

        if( null != idReq && idReq.isRejected()){ 
          end = true;
          //comment decache //context.decache(idReq);
        }
        return end;

    import sailpoint.object.Filter;
    import sailpoint.object.Identity;
    import sailpoint.object.QueryOptions;
    
    int recordCounter = 0; 
    
    Filter managerFilter = Filter.eq("contractorManager", identityName);
    Filter activeFilter = Filter.eq("inactive", false);       
    Filter filter = Filter.and(activeFilter, managerFilter);
                 
    QueryOptions queryOptions = new QueryOptions();
    queryOptions.addFilter(filter);
    queryOptions.setCloneResults(true);
    Iterator objectList = context.search(Identity.class, queryOptions);

		if (objectList != null) {
  		while (objectList.hasNext()) {
    		recordCounter++;
    		Identity idObj = objectList.next();          
        
        if(null != idObj &&  null != identityModel){
          idObj.setAttribute("contractorManager",newContractorManager);
          context.saveObject(idObj);              
          if (0 == (recordCounter % 10)) {
            context.commitTransaction();
        	}
        }        		         
    	}
    	context.commitTransaction();      
    }
    
		Util.flushIterator(objectList);
